arguments.new_str:
using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip default renderer changed; set explicitly to preserve prior look
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }

    [DefaultValue("")]
    public string DisplayName { get; set; } = "";

    [DefaultValue(0)]
    public int MaxItems { get; set; }

    /// <summary>
    /// Shows a drop-down editor, guarding against the .NET 9 nullability
    /// change on <see cref="IWindowsFormsEditorService.DropDownControl"/>.
    /// </summary>
    public static void ShowDropDown(IWindowsFormsEditorService editorService, Control? control)
    {
        if (control is null)
            return;

        editorService.DropDownControl(control);
    }
}

